import re,subprocess
f="blueprint/src/chapters/Picard_TensorObjSubstrate.tex"
def pairs(text,label):
    lines=text.split("\n"); stack=[]; bad=[]
    for i,l in enumerate(lines,1):
        for m in re.finditer(r"\\(begin|end)\{"+label+r"\}",l):
            if m.group(1)=="begin": stack.append(i)
            elif stack: stack.pop()
            else: bad.append(("end",i))
    return stack,bad
