com=subprocess.run(["git","show","HEAD:"+f],capture_output=True,text=True).stdout
for lbl in ["lemma","proof","theorem","definition","remark","corollary","proposition"]:
    s,b=pairs(cur,lbl)
    s2,b2=pairs(com,lbl)
    print(f"{lbl}: CURRENT unmatched_begin={s} stray_end={b} || COMMITTED unmatched_begin={s2} stray_end={b2}")
